-- Module acc00005-0000-0000-0000-000000000005. Namespaced by tag 'buildout' / created_by 'buildout:m33' so pre-existing rows are untouched.
BEGIN;
DELETE FROM question_bank     WHERE module_id='acc00005-0000-0000-0000-000000000005' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='acc00005-0000-0000-0000-000000000005' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='acc00005-0000-0000-0000-000000000005' AND created_by='buildout:m33';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['GNSS is the umbrella term; GPS is the U.S. constellation within it','A receiver needs at least four satellites to solve for X, Y, Z, and the clock bias','Every system has space, control, and user segments','Positioning is trilateration from measured satellite-to-receiver ranges']::text[], learning_objectives=ARRAY['Define GNSS and distinguish it from GPS','Identify the major global and regional satellite constellations','Explain the three segments of a satellite positioning system','Describe the basic principle of trilateration from satellite ranges']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b01-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b01-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['GPS broadcasts on carrier frequencies derived from a 10.23 MHz fundamental','Code-phase measurements are coarse; carrier-phase measurements are precise but ambiguous','The navigation message carries ephemeris (precise orbit) and almanac (coarse, all satellites)','Surveying accuracy comes from resolving the carrier-phase integer ambiguity']::text[], learning_objectives=ARRAY['Describe the GPS carrier frequencies L1, L2, and L5','Distinguish the C/A and P(Y) ranging codes and the navigation message','Explain code-phase vs. carrier-phase observables','Describe satellite orbits, ephemeris, and almanac data']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b02-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b02-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Errors come from satellites, the atmosphere, and the receiver/site','Dual-frequency observations remove most of the ionospheric delay','Multipath is a site-dependent error reduced by antenna choice and siting','Position accuracy = UERE multiplied by the relevant DOP value']::text[], learning_objectives=ARRAY['Identify the major GNSS error sources','Explain ionospheric and tropospheric delay and how each is mitigated','Define multipath and describe field mitigation','Compute position error from UERE and DOP']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b03-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b03-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['GNSS works natively in geocentric ECEF / WGS84 coordinates','A datum is an ellipsoid plus its realization (control + epoch)','State Plane projects a state onto Lambert or transverse Mercator zones','Grid distances differ from ground distances by the combined scale factor']::text[], learning_objectives=ARRAY['Distinguish geocentric, geographic, and projected coordinate systems','Explain reference ellipsoids and horizontal datums (NAD83, WGS84, ITRF)','Describe the State Plane Coordinate System and UTM','Explain the relationship between grid and ground distances']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b04-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b04-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['GNSS measures ellipsoidal height h, not orthometric elevation H','The geoid undulation N converts between them: H = h - N','Orthometric height is what plans, FEMA, and elevations refer to','A current geoid model (e.g., GEOID18) is required for accurate GNSS elevations']::text[], learning_objectives=ARRAY['Distinguish ellipsoidal, orthometric, and geoid heights','Apply the relationship H = h - N','Explain geoid models (GEOID18) and their role in GNSS heighting','Recognize why GNSS gives ellipsoidal height, not elevation']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b05-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b05-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Static surveying is the most accurate relative GNSS technique','Two receivers observing simultaneously form a baseline vector','Longer baselines and weaker geometry require longer occupations','Static is used for control, geodetic ties, and high-accuracy networks']::text[], learning_objectives=ARRAY['Describe static and rapid-static GNSS surveying','Explain baselines, sessions, and occupation times','Describe relative positioning and double differencing conceptually','Identify when static methods are appropriate']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b06-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b06-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['RTK delivers centimeter results in real time using a correction link','A base on known control streams corrections to a moving rover','A "fixed" solution means integer ambiguities are resolved; "float" is not yet reliable','RTK accuracy degrades with baseline length, multipath, and poor geometry']::text[], learning_objectives=ARRAY['Explain the principle of RTK positioning','Describe the base-rover correction link','Distinguish fixed vs. float solutions and initialization','Identify RTK accuracy and limitations']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b07-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b07-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The midterm covers Weeks 1-7','Review signal structure, error sources, datums, geoid heights, static, and RTK','Be able to apply the core computational relationships']::text[], learning_objectives=ARRAY['Review GNSS fundamentals, signals, errors, datums, heights, and methods','Self-assess readiness across the first half of the course','Apply core formulas (H = h - N, baseline error, UERE x DOP)']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b08-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b08-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Network RTK models atmospheric error across a region of reference stations','A VRS synthesizes corrections for a virtual base near the rover','CORS are permanent reference stations providing data for OPUS and post-processing','OPUS returns NSRS coordinates from a submitted static file']::text[], learning_objectives=ARRAY['Explain Network RTK and the VRS concept','Describe the CORS network and its purpose','Explain OPUS and post-processed positioning from CORS','Compare single-base RTK with Network RTK']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b09-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b09-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Mission planning uses the almanac to predict satellite count and DOP','Avoid windows with high PDOP or few satellites','Site recon identifies obstructions, multipath, and access','Match the method (static/RTK/network) to accuracy and logistics']::text[], learning_objectives=ARRAY['Plan a GNSS survey using satellite availability and DOP predictions','Set appropriate elevation masks and observation windows','Conduct site reconnaissance for sky visibility and multipath','Choose the right GNSS method for the accuracy required']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b10-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b10-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Post-processing computes and quality-checks baseline vectors','Loop closures detect blunders in observed baselines','Least-squares adjustment distributes residuals across a redundant network','Adjustment outputs coordinates with error estimates']::text[], learning_objectives=ARRAY['Describe the GNSS baseline post-processing workflow','Explain loop closures and redundancy checks','Explain least-squares network adjustment of GNSS vectors','Interpret adjustment statistics and error ellipses']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b11-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b11-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['GIS stores, analyzes, and displays spatially referenced data','Vector represents discrete features; raster represents continuous grids','Data are organized in thematic layers with attribute tables','Topology encodes spatial relationships like adjacency and connectivity']::text[], learning_objectives=ARRAY['Define GIS and its components','Distinguish vector and raster data models','Explain layers, attributes, and topology','Relate GIS coordinate systems and projections to GNSS data']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b12-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b12-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['GIS data come from GNSS, surveys, imagery, and existing records','Georeferencing ties raster/scanned data to real-world coordinates','Metadata documents source, accuracy, datum, and lineage','Buffer and overlay are core spatial-analysis operations']::text[], learning_objectives=ARRAY['Describe GIS data sources and georeferencing','Explain metadata and the components of spatial data quality','Perform basic spatial analysis: buffers, overlay, clip','Relate GNSS positional accuracy to GIS data quality']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b13-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b13-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Field GNSS data flow into CAD for design and GIS for management','Datum, projection, and geoid model must agree across systems','Grid and ground distances differ by the combined scale factor','Feature codes and standard formats streamline the handoff']::text[], learning_objectives=ARRAY['Describe the GNSS-to-CAD-to-GIS data flow','Explain coordinate/datum reconciliation between field and GIS','Apply grid-to-ground conversion using the combined scale factor','Identify file formats and feature coding for integration']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b14-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b14-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Best practice means redundancy, checks, and documentation','Verify on known control, watch the solution status, and record metadata','The full workflow spans planning, collection, processing, and integration','The final exam covers the entire course']::text[], learning_objectives=ARRAY['Summarize GNSS and GIS best practices for accurate survey data','Review field procedures that ensure quality and redundancy','Review the full GNSS-GIS workflow end to end','Prepare for the final exam']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b15-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b15-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The final is comprehensive, covering Weeks 1-15','Both conceptual and computational questions appear','Master the four core formulas and the full workflow']::text[], learning_objectives=ARRAY['Demonstrate comprehensive mastery of GNSS and GIS applications','Apply all core formulas and concepts from the course','Integrate GNSS field methods with GIS workflows']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc05b16-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc05b16-0000-0000-0000-000000000001';
  'eeee3350-0000-0000-0000-000000000001', 'Orthometric height from ellipsoidal height and geoid undulation', 'Convert a GNSS ellipsoidal height to an orthometric (NAVD88-style) height using the geoid undulation.', 'GNSS/GIS — Height Systems', 'Orthometric height', 'numeric_input', 'easy', 'A GNSS observation gives an ellipsoidal height h = {{h:f2}} m at a point where the geoid model reports an undulation N = {{N:f2}} m. What is the orthometric height H (m)?', 'h - N', '{"decimals":2,"unit":"m","tolerance":0.02}', '[{"name":"h","type":"float","min":150,"max":600,"decimals":2},{"name":"N","type":"float","min":-35,"max":-8,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Apply H = h - N","formula":"H = h - N","calculation_template":"{{h:f2}} - ({{N:f2}})"},{"step_number":2,"title":"Result","result_template":"H = {{_answer}} m"}]'::jsonb, '{"method":"none"}'::jsonb, 'Orthometric height H = h - N = {{h:f2}} - ({{N:f2}}) = {{_answer}} m. The undulation is negative across the lower 48, so subtracting it adds to the ellipsoidal height.', 'acc00005-0000-0000-0000-000000000005', ARRAY['buildout','module-33','practice']::text[], true, 'buildout:m33');
  'eeee3350-0000-0000-0000-000000000002', 'Static baseline error from constant and ppm terms', 'Compute the expected static baseline error from a fixed (mm) plus length-dependent (ppm) specification.', 'GNSS/GIS — Static Surveying', 'Baseline error budget', 'numeric_input', 'medium', 'A static baseline accuracy is specified as {{a}} mm + {{b}} ppm. For a baseline length of {{km}} km, what is the expected error (mm)?', 'a + b*km', '{"decimals":2,"unit":"mm","tolerance":0.1}', '[{"name":"a","type":"integer","min":2,"max":8},{"name":"b","type":"integer","min":1,"max":3},{"name":"km","type":"integer","min":5,"max":30}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Length-dependent term","formula":"b ppm x length","calculation_template":"{{b}} ppm x {{km}} km = {{b}} mm/km x {{km}} km"},{"step_number":2,"title":"Add the constant","result_template":"{{a}} + {{b}} x {{km}} = {{_answer}} mm"}]'::jsonb, '{"method":"none"}'::jsonb, 'One ppm equals 1 mm per km, so the error is a + b*km = {{a}} + {{b}} x {{km}} = {{_answer}} mm.', 'acc00005-0000-0000-0000-000000000005', ARRAY['buildout','module-33','practice']::text[], true, 'buildout:m33');
  'eeee3350-0000-0000-0000-000000000003', 'Position error from UERE and PDOP', 'Compute the expected GNSS position error from the per-satellite range error and the position dilution of precision.', 'GNSS/GIS — Error Analysis', 'UERE and DOP', 'numeric_input', 'easy', 'If the User Equivalent Range Error (UERE) is {{uere:f1}} m and the PDOP is {{pdop:f1}}, what is the expected position error (m)?', 'uere * pdop', '{"decimals":2,"unit":"m","tolerance":0.05}', '[{"name":"uere","type":"float","min":1,"max":6,"decimals":1},{"name":"pdop","type":"float","min":1.5,"max":5,"decimals":1}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Multiply range error by geometry","formula":"sigma = UERE x PDOP","calculation_template":"{{uere:f1}} x {{pdop:f1}}"},{"step_number":2,"title":"Result","result_template":"sigma = {{_answer}} m"}]'::jsonb, '{"method":"none"}'::jsonb, 'Expected position error = UERE x PDOP = {{uere:f1}} x {{pdop:f1}} = {{_answer}} m. Lower PDOP (better geometry) reduces the error.', 'acc00005-0000-0000-0000-000000000005', ARRAY['buildout','module-33','practice']::text[], true, 'buildout:m33');
  'eeee3350-0000-0000-0000-000000000004', 'Grid-to-ground distance using the combined scale factor', 'Convert a grid (state plane) distance to a ground distance using the combined scale factor.', 'GNSS/GIS — Coordinate Systems', 'Grid to ground', 'numeric_input', 'medium', 'A grid distance of {{grid:f2}} ft is to be reduced to the ground using a combined scale factor CSF = {{csf:f5}}. What is the ground distance (ft)?', 'grid / csf', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"grid","type":"float","min":500,"max":5000,"decimals":2},{"name":"csf","type":"float","min":0.99985,"max":1.0001,"decimals":5}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Divide grid by CSF","formula":"ground = grid / CSF","calculation_template":"{{grid:f2}} / {{csf:f5}}"},{"step_number":2,"title":"Result","result_template":"ground = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Grid distance = ground x CSF, so ground = grid / CSF = {{grid:f2}} / {{csf:f5}} = {{_answer}} ft.', 'acc00005-0000-0000-0000-000000000005', ARRAY['buildout','module-33','practice']::text[], true, 'buildout:m33');
COMMIT;
SELECT 'm33 ACC SRVY 2339 — GPS/GIS Applications in Surveying: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='acc00005-0000-0000-0000-000000000005') || ' blocks.' AS status;