INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0001-0000-0000-000000000000', 'acc05b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>From GPS to GNSS</h3><p><strong>GNSS</strong> stands for <em>Global Navigation Satellite System</em>, the generic term for any constellation of satellites that broadcasts ranging signals a receiver can use to compute its position, velocity, and time (PVT). The U.S. <strong>GPS</strong> (Global Positioning System) is one such constellation, but it is no longer alone. Modern survey receivers are <em>multi-constellation</em>, tracking GPS together with Russia&rsquo;s <strong>GLONASS</strong>, the European Union&rsquo;s <strong>Galileo</strong>, and China&rsquo;s <strong>BeiDou</strong>, plus regional systems. Tracking more constellations means more satellites in view, better geometry, faster initialization, and more reliable results under canopy or in urban canyons.</p><p>For a surveyor, the practical takeaway is that &ldquo;GPS&rdquo; in everyday speech usually means <em>GNSS</em>. The hardware, math, and field procedures are largely common across constellations; the receiver simply has more signals to choose from. Throughout this course we use GNSS as the general term and GPS when we mean the U.S. system specifically.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0001-0000-0000-000000000001', 'acc05b01-0000-0000-0000-000000000001', 'table', '{"headers":["System","Operator","Type","Nominal satellites"],"rows":[["GPS","United States","Global","~31 operational"],["GLONASS","Russia","Global","~24"],["Galileo","European Union","Global","~28"],["BeiDou (BDS)","China","Global","~30+"],["QZSS","Japan","Regional (Asia-Pacific)","4+"],["NavIC (IRNSS)","India","Regional","7"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0001-0000-0000-000000000002', 'acc05b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Three segments of every system</h3><p>Each GNSS is organized into three parts. The <strong>space segment</strong> is the constellation of satellites in medium Earth orbit (about 20,200 km for GPS) that broadcast ranging codes and navigation messages. The <strong>control segment</strong> is the network of ground monitoring and uplink stations that track the satellites, compute precise orbits and clock corrections, and upload updated navigation data. The <strong>user segment</strong> is everyone with a receiver &mdash; surveyors, machine-control systems, phones, ships, and aircraft. A failure or degradation in the control segment (bad uploaded ephemeris, for instance) propagates directly into user positions, which is why surveyors verify data quality rather than trusting a fix blindly.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0001-0000-0000-000000000003', 'acc05b01-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"At least four satellites are required for a 3D fix: three to solve the position unknowns (X, Y, Z) and a fourth to solve the receiver clock bias. More satellites improve geometry and provide redundancy."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0001-0000-0000-000000000004', 'acc05b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>How positioning works: trilateration</h3><p>A receiver determines position by <strong>trilateration</strong> from ranges. Each satellite broadcasts a precisely timed signal; the receiver measures how long the signal took to arrive and multiplies by the speed of light to get a <em>range</em>. One range places the receiver somewhere on a sphere around that satellite; two ranges intersect to a circle; three ranges intersect to a point (in principle). Because the receiver&rsquo;s own clock is cheap and inaccurate, the measured ranges are biased by a common clock error &mdash; they are called <strong>pseudoranges</strong>. The fourth satellite lets the receiver solve for that clock bias along with position, which is why four satellites are the practical minimum.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0001-0000-0000-000000000005', 'acc05b01-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["GNSS is the umbrella term; GPS, GLONASS, Galileo, and BeiDou are the four global constellations","Space, control, and user segments make up every system","Trilateration from at least four satellite ranges yields position and receiver clock bias","Multi-constellation receivers see more satellites and produce more robust fixes"]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0002-0000-0000-000000000000', 'acc05b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The GPS signal</h3><p>GPS satellites transmit on several <strong>carrier frequencies</strong> derived from a fundamental 10.23 MHz oscillator. The legacy carriers are <strong>L1 (1575.42 MHz)</strong> and <strong>L2 (1227.60 MHz)</strong>; modernized satellites add <strong>L5 (1176.45 MHz)</strong>. Onto these carriers the satellite modulates two things: <em>ranging codes</em> and a <em>navigation message</em>. The codes are pseudo-random noise (PRN) sequences unique to each satellite, which lets all satellites share the same frequencies (code-division multiple access). The navigation message tells the receiver where the satellite is and how its clock behaves.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0002-0000-0000-000000000001', 'acc05b02-0000-0000-0000-000000000001', 'table', '{"headers":["Signal","Frequency (MHz)","Carries","Notes"],"rows":[["L1","1575.42","C/A code, P(Y), nav msg","Civilian + military"],["L2","1227.60","P(Y), L2C","Dual-frequency ionosphere correction"],["L5","1176.45","Civil safety-of-life","Modernized, high power"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0002-0000-0000-000000000002', 'acc05b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Codes and the navigation message</h3><p>Two ranging codes ride on the carriers. The <strong>C/A code</strong> (Coarse/Acquisition) is the open civilian code on L1; it is easy to acquire and gives meter-level code-phase ranging. The <strong>P(Y) code</strong> (Precise, encrypted) is the military code on L1 and L2. The <strong>navigation message</strong> superimposed on the codes contains the broadcast <strong>ephemeris</strong> (precise orbital parameters for that satellite, valid for a few hours), satellite clock corrections, health flags, and the <strong>almanac</strong> (coarse orbital data for the <em>whole</em> constellation, used for mission planning and acquisition).</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0002-0000-0000-000000000003', 'acc05b02-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Ephemeris = precise orbit for one satellite, short validity. Almanac = coarse orbit for all satellites, long validity. Mission-planning software uses the almanac to predict satellite visibility and geometry."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0002-0000-0000-000000000004', 'acc05b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Code-phase vs. carrier-phase</h3><p>There are two ways to measure range. <strong>Code-phase</strong> ranging correlates the received PRN code with a receiver-generated replica; it is unambiguous but coarse (decimeter-to-meter precision), and is what handheld and navigation receivers use. <strong>Carrier-phase</strong> ranging measures the fraction of a carrier wavelength (about 19 cm on L1) and counts whole cycles; it is roughly 100&times; more precise but carries an unknown <strong>integer ambiguity</strong> &mdash; the number of whole wavelengths between satellite and receiver. Survey-grade positioning (static, RTK, PPK) achieves centimeter accuracy precisely because it resolves that integer ambiguity and uses the carrier phase.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0002-0000-0000-000000000005', 'acc05b02-0000-0000-0000-000000000001', 'equation', '{"latex":"\\phi = N + \\frac{\\Phi}{2\\pi}","label":"Carrier-phase observable: measured fractional phase plus unknown integer N","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0002-0000-0000-000000000006', 'acc05b02-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["L1, L2, and L5 carriers all derive from the 10.23 MHz fundamental frequency","C/A is the open civilian code; P(Y) is encrypted military","Ephemeris is the precise short-term orbit; almanac is the coarse constellation-wide orbit","Carrier-phase ranging is precise but ambiguous; resolving the integer ambiguity gives survey accuracy"]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0003-0000-0000-000000000000', 'acc05b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Where the errors come from</h3><p>Every pseudorange and carrier-phase measurement is corrupted by errors that can be grouped by source. <strong>Satellite errors</strong> include orbit (ephemeris) error and satellite clock error. <strong>Atmospheric errors</strong> are the <em>ionospheric</em> delay (a dispersive, frequency-dependent bending and slowing of the signal in the charged upper atmosphere) and the <em>tropospheric</em> delay (a non-dispersive wet/dry delay in the lower atmosphere). <strong>Receiver and site errors</strong> include receiver clock and noise, antenna phase-center variation, and <strong>multipath</strong> &mdash; signals reflecting off nearby surfaces before reaching the antenna. The combined ranging error per satellite is summarized as the <strong>UERE</strong> (User Equivalent Range Error).</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0003-0000-0000-000000000001', 'acc05b03-0000-0000-0000-000000000001', 'table', '{"headers":["Error source","Typical magnitude","Mitigation"],"rows":[["Satellite clock","~1-2 m","Broadcast/precise corrections"],["Ephemeris (orbit)","~1-2 m","Precise orbits; differential"],["Ionosphere","~5-15 m","Dual-frequency; modeling; differential"],["Troposphere","~0.5-1 m","Models; estimation; differential"],["Multipath","~0.5-3 m","Antenna choice, siting, choke ring"],["Receiver noise","~0.1-1 m","Better receiver/averaging"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0003-0000-0000-000000000002', 'acc05b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Atmospheric delays</h3><p>The <strong>ionosphere</strong> is dispersive: its delay depends on frequency, so a receiver tracking two frequencies (L1 and L2, or L1/L5) can form a linear combination that <em>removes</em> nearly all of the first-order ionospheric error. This is the single biggest advantage of dual-frequency surveying. The <strong>troposphere</strong> is non-dispersive (same delay at all GNSS frequencies), so it cannot be removed by combining frequencies; instead it is handled with models (e.g., Saastamoinen, Hopfield) and, in precise processing, estimated as a parameter. Both delays grow as satellites get lower in the sky, which is why a 10&ndash;15&deg; elevation mask is standard.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0003-0000-0000-000000000003', 'acc05b03-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Multipath cannot be differenced away &mdash; it is unique to each antenna and site. Mitigate it in the field: choose an open site, avoid reflective surfaces (buildings, water, vehicles, chain-link), use a ground plane or choke-ring antenna, and occupy long enough to average it down."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0003-0000-0000-000000000004', 'acc05b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>UERE, DOP, and position accuracy</h3><p>The expected accuracy of a position is the product of the ranging error and the satellite geometry. The <strong>UERE</strong> rolls all per-satellite range errors into one number (a standard deviation in meters). <strong>DOP</strong> (Dilution of Precision) is a unitless multiplier that captures how favorable the satellite geometry is &mdash; satellites well spread across the sky give a low (good) DOP, while clustered satellites give a high (poor) DOP. The expected position error is simply UERE &times; DOP. PDOP (position), HDOP (horizontal), VDOP (vertical), and GDOP (geometric, including time) describe different components.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0003-0000-0000-000000000005', 'acc05b03-0000-0000-0000-000000000001', 'equation', '{"latex":"\\sigma_{pos} = \\text{UERE} \\times \\text{PDOP}","label":"Expected position error from range error and geometry","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0003-0000-0000-000000000006', 'acc05b03-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Errors group into satellite, atmospheric, and receiver/site categories","Dual-frequency removes the first-order ionospheric delay; the troposphere is modeled","Multipath is site-specific and mitigated by antenna and siting, not differencing","Position error = UERE times DOP; good geometry means low DOP"]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0004-0000-0000-000000000000', 'acc05b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Three families of coordinates</h3><p>GNSS positions can be expressed three ways. <strong>Geocentric (ECEF)</strong> coordinates are Cartesian X, Y, Z with the origin at the Earth&rsquo;s mass center &mdash; this is what the receiver actually solves. <strong>Geographic</strong> coordinates are latitude, longitude, and ellipsoidal height referenced to a reference ellipsoid. <strong>Projected (plane)</strong> coordinates are northing and easting on a flat map, produced by a map projection so surveyors can use plane trigonometry. Software converts among these continuously; the surveyor must know which system a coordinate is in before using it.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0004-0000-0000-000000000001', 'acc05b04-0000-0000-0000-000000000001', 'table', '{"headers":["System","Form","Used for"],"rows":[["Geocentric (ECEF)","X, Y, Z meters","GNSS solution, baselines"],["Geographic","Lat, Lon, ellipsoid ht","Datum-level reference"],["Projected (SPC/UTM)","N, E (ft or m)","Mapping, CAD, plats"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0004-0000-0000-000000000002', 'acc05b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Datums and ellipsoids</h3><p>A <strong>horizontal datum</strong> is a reference ellipsoid (a smooth mathematical Earth model with a defined semi-major axis and flattening) plus a <em>realization</em> &mdash; the network of control monuments and an epoch that ties the ellipsoid to the physical Earth. <strong>WGS84</strong> is the GPS native datum; <strong>NAD83</strong> is the North American datum used for U.S. surveying and mapping; <strong>ITRF</strong> is the global reference frame WGS84 is aligned to. NAD83 and WGS84 differ by 1&ndash;2 meters because of how each is defined and because tectonic plates move &mdash; this matters for any survey tying GNSS to published NAD83 control. NGS is replacing NAD83 with new reference frames (e.g., NATRF2022) in the modernized NSRS.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0004-0000-0000-000000000003', 'acc05b04-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"NAD83 and WGS84 are NOT the same datum. Treating GNSS WGS84 coordinates as NAD83 introduces a 1-2 m horizontal shift. Always know and document which datum, realization, and epoch your coordinates use."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0004-0000-0000-000000000004', 'acc05b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>State Plane and UTM projections</h3><p>To work in plane coordinates, surveyors project the ellipsoid onto a flat grid. The <strong>State Plane Coordinate System (SPCS)</strong> divides each state into zones, using a <em>Lambert Conformal Conic</em> projection for zones wider east-west and a <em>Transverse Mercator</em> for zones taller north-south, keeping distortion under about 1:10,000. Texas, for example, has five SPCS zones (North, North Central, Central, South Central, South). <strong>UTM</strong> divides the world into 6&deg;-wide transverse Mercator zones. Because a projection cannot preserve true distance everywhere, grid distances differ from ground distances; the next lessons address heights and scale factors that reconcile them.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0004-0000-0000-000000000005', 'acc05b04-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["ECEF/geographic/projected are three views of the same position","A datum is an ellipsoid plus its control realization and epoch","WGS84 (GPS) and NAD83 (US surveying) differ by 1-2 m","State Plane uses Lambert or transverse Mercator zones to limit distortion"]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0005-0000-0000-000000000000', 'acc05b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Three kinds of height</h3><p>Height is surprisingly subtle in GNSS surveying because three different surfaces are involved. <strong>Ellipsoidal height (h)</strong> is the distance from the reference ellipsoid up to the point, measured along the ellipsoid normal &mdash; this is what GNSS directly produces. <strong>Orthometric height (H)</strong> is the height above the <em>geoid</em> (mean sea level surface) measured along the plumb line &mdash; this is the &ldquo;elevation&rdquo; on plans, benchmarks, and flood maps. The <strong>geoid height or undulation (N)</strong> is the separation between the ellipsoid and the geoid at that point. In the conterminous U.S., N is negative (the geoid lies below the ellipsoid), ranging roughly from &minus;8 m to &minus;53 m.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0005-0000-0000-000000000001', 'acc05b05-0000-0000-0000-000000000001', 'equation', '{"latex":"H = h - N","label":"Orthometric height from ellipsoidal height and geoid undulation","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0005-0000-0000-000000000002', 'acc05b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why this matters in the field</h3><p>A GNSS receiver reports <strong>h</strong>, but a contractor, a benchmark, a FEMA flood elevation, and a topographic plan all use <strong>H</strong>. If you hand a contractor raw ellipsoidal heights, every elevation will be wrong by N &mdash; tens of meters. To get correct elevations you must apply a <strong>geoid model</strong>, which provides N at any latitude/longitude. NGS&rsquo;s <strong>GEOID18</strong> is the current hybrid geoid model for NAD83 in the U.S.; survey software interpolates N from its grid and computes H = h &minus; N automatically when the correct model is loaded.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0005-0000-0000-000000000003', 'acc05b05-0000-0000-0000-000000000001', 'table', '{"headers":["Symbol","Name","Reference surface","Source"],"rows":[["h","Ellipsoidal height","Ellipsoid","GNSS direct"],["H","Orthometric height","Geoid (MSL)","H = h - N"],["N","Geoid undulation","Ellipsoid to geoid","Geoid model (GEOID18)"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0005-0000-0000-000000000004', 'acc05b05-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Never report GNSS ellipsoidal height as elevation. Always apply the correct, current geoid model so that elevations are orthometric (H = h - N). Mixing h and H is a classic, costly blunder on construction and flood work."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0005-0000-0000-000000000005', 'acc05b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Accuracy of GNSS heights</h3><p>GNSS heights are inherently weaker than horizontal positions (VDOP exceeds HDOP because all satellites are above the horizon). Orthometric accuracy is also limited by the geoid model itself. For the best vertical results, surveyors use long static occupations, dual-frequency observations, the latest geoid model, and where elevations are critical they tie to published <strong>NAVD88</strong> benchmarks by leveling rather than trusting GNSS heights alone.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0005-0000-0000-000000000006', 'acc05b05-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["GNSS gives ellipsoidal height h; plans use orthometric elevation H","H = h - N, where N is the geoid undulation from a geoid model","GEOID18 is the current NGS hybrid model for NAD83","GNSS vertical accuracy is weaker than horizontal; verify against benchmarks"]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0006-0000-0000-000000000000', 'acc05b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What static surveying is</h3><p><strong>Static GNSS surveying</strong> is the classic, highest-accuracy relative positioning method. Two or more receivers occupy stations simultaneously and log raw carrier-phase data for an extended period (often 20 minutes to several hours). After the session, the data are post-processed to compute the <strong>baseline vector</strong> (the &Delta;X, &Delta;Y, &Delta;Z) between each pair of receivers. Because errors common to both receivers (satellite clock, much of the orbit and atmosphere) cancel in the differencing, static surveying delivers the best precision available &mdash; millimeters plus a few parts per million of baseline length.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0006-0000-0000-000000000001', 'acc05b06-0000-0000-0000-000000000001', 'table', '{"headers":["Method","Typical occupation","Use"],"rows":[["Static","1-4+ hours","Geodetic control, long baselines"],["Rapid static","5-20 min","Short baselines, densification"],["Kinematic (PPK)","Few seconds/epoch","Many points after init"],["RTK","Real time","Stakeout, topo"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0006-0000-0000-000000000002', 'acc05b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Baselines and differencing</h3><p>A single receiver alone gives an absolute point position limited by all the error sources. <strong>Relative (differential) positioning</strong> instead computes the <em>vector between two receivers</em>. By forming <strong>double differences</strong> &mdash; differencing measurements between two satellites and between two receivers &mdash; the satellite clock error, receiver clock error, and most atmospheric error cancel, and the carrier-phase integer ambiguities become resolvable. The result is a precise baseline that can be adjusted into a network. This is why survey-grade work always uses at least two receivers (or one rover plus a base/CORS).</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0006-0000-0000-000000000003', 'acc05b06-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Occupation time should grow with baseline length and worsening geometry. A short baseline under open sky may need only minutes; a long baseline or obstructed site may need hours to resolve ambiguities reliably."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0006-0000-0000-000000000004', 'acc05b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Baseline error budget</h3><p>Static baseline accuracy is usually quoted as a constant plus a length-dependent term: a few millimeters of fixed error plus a few parts per million (ppm) of the baseline length. For example, a 5 mm + 1 ppm specification on a 10 km baseline gives 5 mm + (1 ppm &times; 10,000 m) = 5 mm + 10 mm = 15 mm. The ppm term reflects errors (orbit, atmosphere) that scale with separation, which is another reason to keep baselines reasonably short and to tie to nearby CORS.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0006-0000-0000-000000000005', 'acc05b06-0000-0000-0000-000000000001', 'equation', '{"latex":"\\sigma = a + b \\cdot D","label":"Baseline error: constant a (mm) plus b (ppm) times length D (km)","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0006-0000-0000-000000000006', 'acc05b06-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Static surveying logs long sessions and post-processes baselines for top accuracy","Two simultaneous receivers form a baseline vector","Double differencing cancels clock and most atmospheric errors","Baseline error = a (mm) + b (ppm) x distance; longer baselines need longer occupations"]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0007-0000-0000-000000000000', 'acc05b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Real-time kinematic positioning</h3><p><strong>RTK</strong> brings carrier-phase, centimeter-level accuracy into the field in <em>real time</em>. A <strong>base</strong> receiver sits on a known point and continuously computes corrections, which it transmits over a radio or cellular link to a <strong>rover</strong>. The rover applies the corrections to its own observations, resolves the carrier-phase ambiguities on the fly, and reports a centimeter-accurate position every second or faster. RTK is the workhorse for topographic mapping, construction stakeout, and as-builts because it is fast and the surveyor sees the result immediately.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0007-0000-0000-000000000001', 'acc05b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Fixed vs. float</h3><p>The single most important indicator on an RTK data collector is the solution status. A <strong>float solution</strong> means the integer ambiguities have not yet been resolved &mdash; the position may be off by decimeters and must not be trusted for survey work. A <strong>fixed solution</strong> means the integers are resolved and the position is good to a centimeter or two. The transition from float to fixed is called <strong>initialization</strong>. Surveyors wait for &ldquo;fixed,&rdquo; verify it on a known point, and re-initialize after any loss of lock (driving under trees, beside buildings).</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0007-0000-0000-000000000002', 'acc05b07-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Never record RTK points on a FLOAT solution. Only a FIXED (ambiguity-resolved) solution gives survey-grade accuracy. Always check into a known point at the start and periodically to confirm the fix is valid."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0007-0000-0000-000000000003', 'acc05b07-0000-0000-0000-000000000001', 'table', '{"headers":["Solution","Ambiguities","Typical accuracy","Trust for survey?"],"rows":[["Autonomous","none","meters","No"],["DGPS/code","code only","sub-meter","No (mapping only)"],["Float","not resolved","decimeters","No"],["Fixed","resolved","1-2 cm + 1 ppm","Yes"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0007-0000-0000-000000000004', 'acc05b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>RTK accuracy and limits</h3><p>A fixed RTK solution is typically good to about 1&ndash;2 cm horizontally and 2&ndash;3 cm vertically, with a small ppm term that grows with the base-rover distance. Single-base RTK is generally reliable out to about 10&ndash;20 km before the correction loses validity (the atmosphere over base and rover diverges). RTK is degraded by multipath, overhead obstructions, weak radio/cell coverage, and poor geometry. For larger areas or longer ranges, surveyors move to <strong>Network RTK</strong> (next lesson), which models the atmosphere across a region of reference stations.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0007-0000-0000-000000000005', 'acc05b07-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["RTK gives real-time centimeter positions via a base-to-rover correction link","Only a FIXED solution is survey-grade; FLOAT is not","Initialization is the float-to-fixed transition; re-initialize after loss of lock","Single-base RTK is reliable to roughly 10-20 km"]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0008-0000-0000-000000000000', 'acc05b08-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Midterm overview</h3><p>The Week 8 midterm covers the first half of the course: GNSS fundamentals and constellations (Week 1), signal structure and orbits (Week 2), error sources and mitigation (Week 3), coordinate systems and datums (Week 4), geoid models and heights (Week 5), static surveying (Week 6), and RTK (Week 7). Expect a mix of conceptual multiple-choice questions and short computations.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0008-0000-0000-000000000001', 'acc05b08-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What to be able to do</h3><p>You should be able to: name the four global constellations and the three system segments; explain code-phase vs. carrier-phase and the integer ambiguity; list and mitigate the major error sources; convert between ellipsoidal and orthometric height with <strong>H = h &minus; N</strong>; compute expected position error as <strong>UERE &times; DOP</strong>; estimate a static <strong>baseline error as a + b&middot;D</strong>; and explain the difference between fixed and float RTK solutions and between WGS84 and NAD83.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0008-0000-0000-000000000002', 'acc05b08-0000-0000-0000-000000000001', 'table', '{"headers":["Topic","Week","Core idea"],"rows":[["Constellations/segments","1","GNSS, space/control/user"],["Signals/observables","2","Code vs. carrier, ambiguity"],["Errors/DOP","3","UERE x DOP"],["Datums/projections","4","WGS84 vs NAD83, SPC"],["Heights/geoid","5","H = h - N"],["Static","6","Baselines, a + b*D"],["RTK","7","Fixed vs float"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0008-0000-0000-000000000003', 'acc05b08-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Bring a calculator. Practice the four formula types: H = h - N; baseline a + b*D; UERE x PDOP; and grid/ground scale factor conversions."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0008-0000-0000-000000000004', 'acc05b08-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["The midterm spans Weeks 1-7","Master the four core formulas and the conceptual distinctions","Know fixed vs. float and WGS84 vs. NAD83 cold"]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0009-0000-0000-000000000000', 'acc05b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Beyond a single base</h3><p>Single-base RTK weakens as the rover moves away from the base because the atmosphere over the two sites diverges. <strong>Network RTK</strong> solves this by using a network of permanent reference stations. A central server collects all their data, models the spatially-varying errors (ionosphere, troposphere, orbits) across the whole region, and generates corrections valid anywhere inside the network. The rover sends its approximate position to the server and receives tailored corrections &mdash; extending reliable centimeter RTK across tens of kilometers without a local base.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0009-0000-0000-000000000001', 'acc05b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>VRS and other network methods</h3><p>The most common implementation is the <strong>Virtual Reference Station (VRS)</strong>: the network synthesizes corrections as if a base existed right next to the rover (the &ldquo;virtual&rdquo; station), so the baseline is effectively near zero and the rover behaves like it has a base a few meters away. Other approaches include MAC and FKP. All require a two-way data link (cellular) so the rover can send its position and receive corrections. The surveyor subscribes to a network RTK service rather than setting up and occupying a physical base.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0009-0000-0000-000000000002', 'acc05b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>CORS and OPUS</h3><p>The U.S. <strong>CORS</strong> (Continuously Operating Reference Stations) network, coordinated by NGS, is a set of permanent GNSS stations with precisely known NSRS coordinates that log data continuously and make it freely available. CORS underpin Network RTK and post-processing: a surveyor can collect a static file at an unknown point and process it against nearby CORS. NGS&rsquo;s <strong>OPUS</strong> (Online Positioning User Service) automates this &mdash; you upload a dual-frequency static file, and OPUS returns NSRS coordinates (NAD83 and ITRF, with state plane and UTM) by processing against three CORS. OPUS-S works on 15 min&ndash;48 hr of data.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0009-0000-0000-000000000003', 'acc05b09-0000-0000-0000-000000000001', 'table', '{"headers":["Tool","What it is","Use"],"rows":[["CORS","Permanent NGS reference stations","Data for processing"],["OPUS","Online static processing service","Coordinates from a file"],["Network RTK / VRS","Modeled real-time corrections","Field RTK over wide area"],["Single-base RTK","One local base + rover","Local centimeter work"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0009-0000-0000-000000000004', 'acc05b09-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"OPUS is free and authoritative: submit a quality dual-frequency static occupation (longer is better) and receive published-grade NSRS coordinates tied to the national network &mdash; ideal for establishing project control."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0009-0000-0000-000000000005', 'acc05b09-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Network RTK models regional atmospheric error using many reference stations","VRS synthesizes a virtual base next to the rover","CORS are permanent NGS stations supplying free continuous data","OPUS post-processes a submitted static file into NSRS coordinates"]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0010-0000-0000-000000000000', 'acc05b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why plan?</h3><p>Although modern multi-constellation receivers see many satellites, planning still prevents wasted trips. <strong>Mission-planning software</strong> uses a current <em>almanac</em> and the site coordinates to predict, for any time window, how many satellites will be visible, where they will be (sky plot), and what the DOP values will be. The surveyor schedules critical occupations for windows with adequate satellites and low PDOP, and avoids the brief windows when geometry is poor.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0010-0000-0000-000000000001', 'acc05b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Elevation mask and obstructions</h3><p>An <strong>elevation mask</strong> (commonly 10&ndash;15&deg;) tells the receiver to ignore satellites below that angle, because low satellites suffer the most atmospheric delay and multipath. During <strong>site reconnaissance</strong>, the surveyor evaluates each station&rsquo;s sky visibility, sketches obstructions (buildings, trees, terrain) on an obstruction diagram, and identifies reflective surfaces that cause multipath. Stations under heavy canopy, beside tall buildings, or near water may need a different method, a longer occupation, or relocation.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0010-0000-0000-000000000002', 'acc05b10-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Set a 10-15 degree elevation mask to suppress the noisiest low-elevation signals. On an obstructed site, mission planning helps you pick the window when the visible satellites are well distributed."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0010-0000-0000-000000000003', 'acc05b10-0000-0000-0000-000000000001', 'table', '{"headers":["Need","Method","Why"],"rows":[["Geodetic control","Static / OPUS","Highest accuracy"],["Topo over a wide area","Network RTK","No local base needed"],["Local stakeout","Single-base RTK","Fast, immediate"],["Many points, post-process ok","PPK","Efficient, robust"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0010-0000-0000-000000000004', 'acc05b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Choosing the method</h3><p>Planning includes matching technique to the job. High-accuracy control favors <strong>static</strong> or <strong>OPUS</strong>. Wide-area topo favors <strong>Network RTK</strong>. Tight local stakeout favors <strong>single-base RTK</strong>. Where real-time links are unreliable, <strong>PPK</strong> (post-processed kinematic) collects data for later processing. The plan also covers control to occupy, redundancy (repeat occupations on independent windows), equipment, datum/geoid model, and how results will tie to published control.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0010-0000-0000-000000000005', 'acc05b10-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Mission planning uses the almanac to forecast satellite count and DOP","A 10-15 degree elevation mask suppresses noisy low signals","Site recon documents obstructions and multipath risk","Match the GNSS method to the required accuracy and site conditions"]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0011-0000-0000-000000000000', 'acc05b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>From raw data to coordinates</h3><p>Post-processed GNSS work proceeds in stages. First, raw observation files (often in the <strong>RINEX</strong> exchange format) from each receiver are imported. The software computes each <strong>baseline vector</strong> by double-differencing and resolving ambiguities, reporting a solution type (fixed is best) and a quality estimate. The baselines, together with their covariances, become the observations for a network adjustment that yields final coordinates on the project datum.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0011-0000-0000-000000000001', 'acc05b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Loop closures and redundancy</h3><p>Before adjusting, surveyors check <strong>loop closures</strong>: a closed loop of baselines should sum to zero, so any large misclosure flags a blunder in one of the vectors. Independent baselines (from different sessions or satellite geometry) provide <strong>redundancy</strong> &mdash; the extra observations that let the adjustment detect and absorb small errors. A network with no redundancy cannot be checked; good GNSS networks deliberately observe more baselines than the minimum.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0011-0000-0000-000000000002', 'acc05b11-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Redundancy is the surveyor''s safety net. Observe more baselines than strictly necessary so loop closures and the least-squares adjustment can catch blunders and quantify accuracy."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0011-0000-0000-000000000003', 'acc05b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Least-squares network adjustment</h3><p>A <strong>least-squares adjustment</strong> takes all the redundant baseline observations and finds the set of coordinates that best fits them by minimizing the weighted sum of squared residuals. Holding one or more control stations fixed (a <em>constrained</em> adjustment) ties the network to the published datum. The adjustment reports residuals, a reference variance (which should be near 1 if the error model is right), and <strong>error ellipses</strong> showing the positional uncertainty of each station. These statistics are the surveyor&rsquo;s evidence that the network meets accuracy standards.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0011-0000-0000-000000000004', 'acc05b11-0000-0000-0000-000000000001', 'table', '{"headers":["Step","Output","Check"],"rows":[["Import RINEX","Observations","Antenna heights, names"],["Process baselines","Vectors + covariance","Fixed solution"],["Loop closures","Misclosures","Within tolerance"],["Minimally constrained adj.","Internal fit","Reference variance ~1"],["Constrained adj.","Final coordinates","Fits control"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0011-0000-0000-000000000005', 'acc05b11-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Post-processing computes baseline vectors from RINEX data","Loop closures and redundancy catch blunders","Least-squares adjustment yields best-fit coordinates and error estimates","A constrained adjustment ties the network to published control"]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0012-0000-0000-000000000000', 'acc05b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What a GIS is</h3><p>A <strong>Geographic Information System (GIS)</strong> is software (and the associated data, people, and procedures) for capturing, storing, analyzing, and displaying data tied to locations on the Earth. Unlike a static map, a GIS links <em>geometry</em> (where features are) with <em>attributes</em> (what they are) in a database, so you can query, measure, and analyze relationships. Surveyors feed authoritative, high-accuracy field data into GIS and increasingly consume GIS data for parcels, utilities, and base mapping.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0012-0000-0000-000000000001', 'acc05b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Vector and raster</h3><p>GIS uses two fundamental data models. The <strong>vector</strong> model represents discrete features as <em>points</em> (a well, a monument), <em>lines</em> (a road, a pipe), and <em>polygons</em> (a parcel, a lake), each with coordinates and an attribute record. The <strong>raster</strong> model represents continuous phenomena as a grid of cells, each holding a value &mdash; aerial imagery, elevation (a DEM), or land cover. Vector is precise and compact for boundaries and networks; raster is natural for surfaces and imagery. Many projects use both.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0012-0000-0000-000000000002', 'acc05b12-0000-0000-0000-000000000001', 'table', '{"headers":["Model","Represents","Examples","Strength"],"rows":[["Vector - point","Discrete locations","Monuments, wells","Exact position"],["Vector - line","Linear features","Roads, pipes","Networks"],["Vector - polygon","Areas","Parcels, zoning","Boundaries"],["Raster","Continuous grids","Imagery, DEM","Surfaces"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0012-0000-0000-000000000003', 'acc05b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Layers, attributes, and topology</h3><p>GIS organizes data into thematic <strong>layers</strong> (parcels, streets, utilities, contours) that overlay in a common coordinate system. Each vector feature links to a row in an <strong>attribute table</strong> &mdash; the descriptive data (owner, diameter, elevation). <strong>Topology</strong> is the set of rules encoding spatial relationships independent of exact coordinates: which polygons are adjacent, whether lines connect at nodes, whether parcels overlap or leave gaps. Topology enforces data integrity (no parcel gaps/overlaps) and enables analysis like tracing a network.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0012-0000-0000-000000000004', 'acc05b12-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"For GIS to be useful, every layer must share a defined coordinate system and projection. Mismatched or undefined projections are the most common reason layers do not line up."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0012-0000-0000-000000000005', 'acc05b12-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["GIS links geometry with attributes in a spatial database","Vector = discrete points/lines/polygons; raster = continuous grid cells","Data are organized in layers, each feature having an attribute record","Topology encodes adjacency, connectivity, and integrity rules"]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0013-0000-0000-000000000000', 'acc05b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Getting data into GIS</h3><p>GIS data come from many sources: <strong>GNSS field collection</strong> (the surveyor&rsquo;s contribution), conventional surveys, aerial and satellite <strong>imagery</strong>, LiDAR, scanned historical maps, and existing digital records. Raster and scanned sources must be <strong>georeferenced</strong> &mdash; assigned real-world coordinates &mdash; by matching identifiable control points (road intersections, monuments) to known coordinates so the image overlays correctly with other layers. Field GNSS data, by contrast, already carry coordinates and are imported directly.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0013-0000-0000-000000000001', 'acc05b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Data quality and metadata</h3><p>Not all GIS data are equally trustworthy. <strong>Spatial data quality</strong> has several components: <em>positional accuracy</em> (how close geometry is to truth), <em>attribute accuracy</em> (are the descriptive values correct), <em>completeness</em>, <em>logical consistency</em> (topology valid), and <em>lineage</em> (the data&rsquo;s history and processing). <strong>Metadata</strong> &mdash; &ldquo;data about the data&rdquo; &mdash; documents all of this: source, collection method, datum and projection, accuracy, date, and steps applied. Surveyors providing data to a GIS should deliver complete metadata so downstream users know the datum, epoch, and accuracy.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0013-0000-0000-000000000002', 'acc05b13-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"A GIS layer is only as reliable as its worst input. Sub-meter mapping-grade GNSS is fine for asset inventory but must never be confused with survey-grade boundary data. Document accuracy in metadata so users do not over-trust the layer."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0013-0000-0000-000000000003', 'acc05b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Core spatial analysis</h3><p>GIS earns its keep through analysis. A <strong>buffer</strong> creates a zone of a specified distance around features (e.g., a 100-ft wetland setback). <strong>Overlay</strong> operations combine layers: a <em>union</em> keeps everything, an <em>intersect</em> keeps only the common area, a <em>clip</em> cuts one layer to the outline of another. <strong>Spatial queries</strong> select features by location (&ldquo;parcels within 500 ft of the floodplain&rdquo;). These tools turn raw layers into answers &mdash; which is exactly where accurate GNSS-collected geometry pays off.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0013-0000-0000-000000000004', 'acc05b13-0000-0000-0000-000000000001', 'table', '{"headers":["Operation","What it does","Example"],"rows":[["Buffer","Zone around features","Setback, easement width"],["Intersect","Common area of two layers","Parcels in floodplain"],["Union","All area of two layers","Combined coverage"],["Clip","Cut layer to a boundary","Trim data to county"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0013-0000-0000-000000000005', 'acc05b13-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["GIS data come from GNSS, surveys, imagery, and records; rasters need georeferencing","Quality = positional + attribute accuracy + completeness + consistency + lineage","Metadata documents source, datum, accuracy, and processing","Buffer and overlay (intersect/union/clip) are core analysis tools"]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0014-0000-0000-000000000000', 'acc05b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The integrated workflow</h3><p>A surveyor&rsquo;s GNSS observations rarely live in isolation. The typical flow is: collect points and linework in the field with <strong>feature codes</strong>, reduce and adjust the data, bring it into <strong>CAD</strong> for design, plats, and earthwork, and publish it to <strong>GIS</strong> for long-term asset and parcel management. Each handoff must preserve coordinate system, units, and accuracy. The surveyor is often the source of the most accurate geometry in the entire enterprise GIS, so clean integration matters.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0014-0000-0000-000000000001', 'acc05b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Grid vs. ground distances</h3><p>The biggest integration pitfall is mixing <strong>grid</strong> and <strong>ground</strong> coordinates. State plane coordinates are <em>grid</em> values: a horizontal distance computed from them differs from the distance you would tape on the ground because of two effects. The <strong>scale factor</strong> accounts for the map projection, and the <strong>elevation (sea-level) factor</strong> accounts for reducing a distance at elevation down to the ellipsoid. Their product is the <strong>combined scale factor (CSF)</strong>. Ground distance times CSF gives grid distance; grid distance divided by CSF gives ground.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0014-0000-0000-000000000002', 'acc05b14-0000-0000-0000-000000000001', 'equation', '{"latex":"D_{grid} = D_{ground} \\times CSF, \\quad CSF = k \\times \\frac{R}{R+h}","label":"Combined scale factor: projection scale k times elevation factor","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0014-0000-0000-000000000003', 'acc05b14-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs in practice: many Texas projects use surface (ground) coordinate systems or a Texas-specific low-distortion / \"surface adjustment factor\" so that CAD distances match taped ground distances. Always confirm whether a deliverable is on grid or surface coordinates before combining datasets."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0014-0000-0000-000000000004', 'acc05b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Formats and coding</h3><p>Integration relies on common formats: <strong>RINEX</strong> for raw GNSS, ASCII point files (PNEZD), <strong>LandXML</strong> for survey/design exchange, DWG/DXF for CAD, and shapefile/geodatabase/GeoPackage for GIS. <strong>Feature coding</strong> in the field (assigning each shot a code like EP for edge-of-pavement) lets software draw linework and assign GIS attributes automatically. Consistent datum, projection, geoid model, and units across all these formats is what keeps the data lining up.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0014-0000-0000-000000000005', 'acc05b14-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Field GNSS data flow through CAD into GIS; each step must preserve datum and units","Grid and ground distances differ by the combined scale factor (CSF)","D_grid = D_ground x CSF; divide by CSF to go grid to ground","Texas often uses surface/low-distortion coordinates so ground = CAD distances"]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0015-0000-0000-000000000000', 'acc05b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Field best practices</h3><p>Accurate GNSS work is disciplined work. <strong>Check into known control</strong> at the start and periodically. Record only <strong>fixed</strong> RTK solutions and watch PDOP and the number of satellites. Build in <strong>redundancy</strong> &mdash; observe key points twice on independent geometry. Measure and record <strong>antenna heights</strong> carefully (a classic blunder source). Apply the correct <strong>datum and geoid model</strong>. Document everything: occupation times, equipment, datum, epoch, and accuracy. These habits turn raw fixes into defensible survey data.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0015-0000-0000-000000000001', 'acc05b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>GIS and integration best practices</h3><p>On the GIS side, define and carry a consistent coordinate system on every layer, deliver complete <strong>metadata</strong> stating datum, projection, geoid model, and accuracy, and never let mapping-grade data masquerade as survey-grade. When moving data between field, CAD, and GIS, confirm grid vs. ground, units, and the combined scale factor. Keeping the lineage documented protects both the surveyor and the downstream users.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0015-0000-0000-000000000002', 'acc05b15-0000-0000-0000-000000000001', 'table', '{"headers":["Stage","Best practice"],"rows":[["Planning","Mission plan, recon, choose method"],["Field","Check control, fixed only, redundancy, antenna heights"],["Processing","Loop closures, least-squares, statistics"],["Integration","Consistent datum/units, metadata, grid vs ground"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0015-0000-0000-000000000003', 'acc05b15-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"When in doubt, add redundancy and write it down. A second independent observation and complete metadata resolve most disputes about GNSS data quality."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0015-0000-0000-000000000004', 'acc05b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Course review</h3><p>The course has moved from satellite signals (Weeks 1&ndash;2), through errors and reference frames (Weeks 3&ndash;5), the major survey methods (Weeks 6&ndash;7, 9&ndash;11), into GIS and integration (Weeks 12&ndash;14). The unifying theme is turning satellite ranges into trustworthy, documented spatial data that flows cleanly into CAD and GIS. Review the four core computations (H = h &minus; N; baseline a + b&middot;D; UERE &times; DOP; grid/ground CSF) and the key conceptual distinctions for the final.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0015-0000-0000-000000000005', 'acc05b15-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Redundancy, control checks, and documentation are the heart of best practice","Record only fixed solutions; measure antenna heights carefully","Carry a consistent coordinate system and complete metadata into GIS","The final exam covers the entire GNSS-to-GIS workflow"]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0016-0000-0000-000000000000', 'acc05b16-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Final exam overview</h3><p>The Week 16 final is comprehensive, spanning the entire course: GNSS fundamentals and constellations, signal structure and observables, error sources and DOP, datums and projections, geoid heights, static and RTK methods, Network RTK/CORS/OPUS, survey and mission planning, data processing and adjustment, GIS fundamentals, GIS data quality and analysis, and GNSS-CAD-GIS integration.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0016-0000-0000-000000000001', 'acc05b16-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What you should master</h3><p>Be ready to apply the four core computations: orthometric height <strong>H = h &minus; N</strong>; static baseline error <strong>a + b&middot;D</strong>; expected position error <strong>UERE &times; DOP</strong>; and grid/ground conversion via the <strong>combined scale factor</strong>. Be ready to explain code vs. carrier phase and the integer ambiguity, fixed vs. float, WGS84 vs. NAD83, vector vs. raster, topology, georeferencing, metadata, and the role of CORS and OPUS. Scenario questions will ask you to choose the right method and reconcile coordinate systems.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0016-0000-0000-000000000002', 'acc05b16-0000-0000-0000-000000000001', 'table', '{"headers":["Half","Weeks","Emphasis"],"rows":[["First","1-7","Signals, errors, datums, heights, static, RTK"],["Second","9-15","Network RTK, planning, adjustment, GIS, integration"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0016-0000-0000-000000000003', 'acc05b16-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Review the four formulas and practice one numeric example of each. Then review the conceptual distinctions; many final questions are scenario-based choices among methods and coordinate systems."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3310-0016-0000-0000-000000000004', 'acc05b16-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["The final is comprehensive across Weeks 1-15","Apply all four core formulas confidently","Explain the key conceptual distinctions and choose appropriate methods"]}'::jsonb, 4);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000001', 'GNSS', 'Global Navigation Satellite System &mdash; the generic term for any satellite positioning constellation; GPS is the U.S. example.', 'U is for "universal/umbrella" term', 'acc00005-0000-0000-0000-000000000005', 'acc05b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000002', 'Pseudorange', 'A satellite-to-receiver range computed from signal travel time that is biased by the receiver clock error.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000003', 'Three segments', 'Space (satellites), control (ground tracking/upload stations), and user (receivers).', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000004', 'Ephemeris vs. almanac', 'Ephemeris is precise orbit data for one satellite valid a few hours; almanac is coarse orbit data for the whole constellation valid weeks.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000005', 'Integer ambiguity', 'The unknown whole number of carrier wavelengths between satellite and receiver that must be resolved for centimeter accuracy.', 'It is an integer count of full cycles', 'acc00005-0000-0000-0000-000000000005', 'acc05b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000006', 'C/A code', 'The open Coarse/Acquisition pseudo-random code on L1 used for civilian code-phase ranging.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000007', 'UERE', 'User Equivalent Range Error &mdash; the combined one-sigma ranging error per satellite, in meters.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000008', 'Dilution of Precision (DOP)', 'A unitless multiplier describing satellite geometry; low DOP = good geometry. Position error = UERE x DOP.', 'Lower is better', 'acc00005-0000-0000-0000-000000000005', 'acc05b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000009', 'Multipath', 'Error caused by signals reflecting off nearby surfaces before reaching the antenna; reduced by siting and antenna design.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000010', 'Horizontal datum', 'A reference ellipsoid plus its realization (control + epoch) that defines latitude and longitude.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000011', 'State Plane Coordinate System', 'A conformal plane-grid system dividing each state into zones (Lambert conic or transverse Mercator) with distortion held under ~1:10,000.', 'Texas has five of these zones', 'acc00005-0000-0000-0000-000000000005', 'acc05b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000012', 'ECEF', 'Earth-Centered, Earth-Fixed geocentric Cartesian X, Y, Z coordinates &mdash; the native frame of a GNSS solution.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000013', 'Geoid undulation (N)', 'The separation between the ellipsoid and the geoid at a point; used to convert h to H. Negative across the lower 48 states.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000014', 'H = h - N', 'Orthometric height equals ellipsoidal height minus geoid undulation.', 'GNSS gives h; subtract N', 'acc00005-0000-0000-0000-000000000005', 'acc05b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000015', 'GEOID18', 'The current NGS hybrid geoid model that supplies N for converting GNSS ellipsoidal heights to NAVD88-style orthometric elevations.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000016', 'Baseline', 'The 3D vector (delta X, Y, Z) between two simultaneously observing GNSS receivers.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000017', 'Double differencing', 'Forming differences between two satellites and two receivers to cancel clock and atmospheric errors and enable ambiguity resolution.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000018', 'Rapid static', 'A short-occupation static method (minutes) for short baselines and control densification.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000019', 'RTK', 'Real-Time Kinematic &mdash; carrier-phase positioning that yields centimeter accuracy in real time using base-to-rover corrections.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000020', 'Fixed solution', 'An RTK solution with integer ambiguities resolved, accurate to a centimeter or two. (Float = unresolved, not trustworthy.)', 'The good one to record', 'acc00005-0000-0000-0000-000000000005', 'acc05b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000021', 'Initialization', 'The process of resolving ambiguities so the solution transitions from float to fixed.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000022', 'Midterm scope', 'Weeks 1-7: fundamentals, signals, errors, datums, heights, static, and RTK.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b08-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000023', 'Core formulas', 'H = h - N; baseline error a + b*D; position error UERE x DOP; grid = ground x combined scale factor.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b08-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000024', 'Network RTK / VRS', 'Real-time corrections modeled across a network of reference stations; VRS synthesizes a virtual base near the rover.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000025', 'CORS', 'Continuously Operating Reference Stations &mdash; permanent NGS GNSS stations with known coordinates and free data.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000026', 'OPUS', 'NGS Online Positioning User Service; returns NSRS coordinates from an uploaded static file processed against CORS.', 'Online + upload a static file', 'acc00005-0000-0000-0000-000000000005', 'acc05b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000027', 'Mission planning', 'Using almanac data and site coordinates to predict satellite visibility, sky geometry, and DOP for scheduling observations.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000028', 'Elevation mask', 'The cutoff angle (commonly 10-15 deg) below which the receiver ignores satellites to reduce atmospheric and multipath error.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000029', 'Obstruction diagram', 'A site-recon sketch of azimuth/elevation of obstructions around a station used to assess sky visibility.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000030', 'RINEX', 'Receiver Independent Exchange format &mdash; the standard raw GNSS observation file format for post-processing.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000031', 'Loop closure', 'The misclosure of a closed loop of baselines, which should sum to zero; large values flag a blunder.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000032', 'Least-squares adjustment', 'A method that distributes residuals across a redundant network to find best-fit coordinates and their uncertainties.', 'Minimizes weighted squared residuals', 'acc00005-0000-0000-0000-000000000005', 'acc05b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000033', 'Vector vs. raster', 'Vector represents discrete features as points/lines/polygons; raster represents continuous phenomena as a grid of cells.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000034', 'Attribute table', 'The database table linking each GIS feature to its descriptive data (owner, size, type).', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000035', 'Topology', 'Rules encoding spatial relationships (adjacency, connectivity) and enforcing integrity such as no gaps or overlaps between polygons.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000036', 'Georeferencing', 'Assigning real-world coordinates to a raster/scanned image by matching control points so it overlays other layers.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000037', 'Metadata', '"Data about the data" &mdash; documentation of source, datum, projection, accuracy, date, and lineage.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000038', 'Buffer', 'A spatial-analysis operation creating a zone of specified distance around features.', 'Think setback or easement', 'acc00005-0000-0000-0000-000000000005', 'acc05b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000039', 'Combined scale factor (CSF)', 'The product of the projection scale factor and the elevation factor; converts between ground and grid distances.', 'Multiply ground by it to get grid', 'acc00005-0000-0000-0000-000000000005', 'acc05b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000040', 'Grid vs. ground distance', 'Grid is the distance on the projection (state plane); ground is the taped horizontal distance at elevation. They differ by the CSF.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000041', 'Feature code', 'A field-assigned code (e.g., EP for edge of pavement) that drives automatic linework and GIS attribute assignment.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000042', 'Redundancy (best practice)', 'Observing key points more than once on independent geometry so blunders can be detected and accuracy quantified.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000043', 'Antenna height blunder', 'A common error source; always measure and record antenna height (and measurement type) carefully.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000044', 'Lineage documentation', 'Recording the source, datum, epoch, processing, and accuracy of data so its quality is defensible.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000045', 'Final exam scope', 'Comprehensive: all GNSS and GIS topics from Weeks 1-15.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3340-0000-0000-0000-000000000046', 'Four core formulas', 'H = h - N; baseline a + b*D; UERE x DOP; grid = ground x CSF.', NULL, 'acc00005-0000-0000-0000-000000000005', 'acc05b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-33']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000001', 'How many satellites are required at minimum for a 3D GNSS position fix?', 'multiple_choice', '["Two","Three","Four","Six"]'::jsonb, 'Four', 'Three satellites solve X, Y, Z; a fourth is needed to solve the receiver clock bias, so four is the minimum.', 'easy', 'acc00005-0000-0000-0000-000000000005', 'acc05b01-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000002', 'Which of the following is NOT one of the four global GNSS constellations?', 'multiple_choice', '["GPS","GLONASS","QZSS","Galileo"]'::jsonb, 'QZSS', 'QZSS is a regional (Asia-Pacific) system. The four global constellations are GPS, GLONASS, Galileo, and BeiDou.', 'medium', 'acc00005-0000-0000-0000-000000000005', 'acc05b01-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000003', 'The GPS L1 carrier is broadcast at which frequency?', 'multiple_choice', '["1176.45 MHz","1227.60 MHz","1575.42 MHz","10.23 MHz"]'::jsonb, '1575.42 MHz', 'L1 is 1575.42 MHz. L2 is 1227.60, L5 is 1176.45, and 10.23 MHz is the fundamental frequency.', 'medium', 'acc00005-0000-0000-0000-000000000005', 'acc05b02-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000004', 'Survey-grade centimeter accuracy depends primarily on resolving what?', 'multiple_choice', '["The receiver clock","The carrier-phase integer ambiguity","The almanac","The C/A code"]'::jsonb, 'The carrier-phase integer ambiguity', 'Carrier phase is precise but ambiguous by an integer number of wavelengths; resolving that integer gives centimeter accuracy.', 'medium', 'acc00005-0000-0000-0000-000000000005', 'acc05b02-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000005', 'Which error source can be largely removed by using dual-frequency observations?', 'multiple_choice', '["Tropospheric delay","Multipath","Ionospheric delay","Receiver noise"]'::jsonb, 'Ionospheric delay', 'The ionosphere is dispersive (frequency-dependent), so combining two frequencies removes most of its delay. The troposphere is non-dispersive.', 'medium', 'acc00005-0000-0000-0000-000000000005', 'acc05b03-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000006', 'If the UERE is 3.0 m and the PDOP is 2.5, what is the expected position error in meters?', 'numeric_input', '[]'::jsonb, '7.5', 'Position error = UERE x PDOP = 3.0 x 2.5 = 7.5 m.', 'easy', 'acc00005-0000-0000-0000-000000000005', 'acc05b03-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000007', 'WGS84 and NAD83 coordinates for the same point differ by approximately:', 'multiple_choice', '["0 (they are identical)","1-2 meters","100 meters","1 kilometer"]'::jsonb, '1-2 meters', 'The two datums are defined differently and the plates move, so they differ by 1-2 m. They are not interchangeable.', 'medium', 'acc00005-0000-0000-0000-000000000005', 'acc05b04-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000008', 'The State Plane Coordinate System uses which projection for zones that are wider east-to-west?', 'multiple_choice', '["Transverse Mercator","Lambert Conformal Conic","UTM","Stereographic"]'::jsonb, 'Lambert Conformal Conic', 'Lambert conic is used for east-west wide zones; transverse Mercator for north-south tall zones.', 'medium', 'acc00005-0000-0000-0000-000000000005', 'acc05b04-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000009', 'A GNSS receiver directly measures which type of height?', 'multiple_choice', '["Orthometric height (H)","Ellipsoidal height (h)","Geoid height (N)","Mean sea level"]'::jsonb, 'Ellipsoidal height (h)', 'GNSS gives ellipsoidal height h; orthometric H must be derived using H = h - N with a geoid model.', 'easy', 'acc00005-0000-0000-0000-000000000005', 'acc05b05-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000010', 'A point has ellipsoidal height h = 250.00 m and geoid undulation N = -25.00 m. What is the orthometric height H in meters?', 'numeric_input', '[]'::jsonb, '275.00', 'H = h - N = 250.00 - (-25.00) = 275.00 m.', 'medium', 'acc00005-0000-0000-0000-000000000005', 'acc05b05-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000011', 'The vector (delta X, Y, Z) between two simultaneously observing receivers is called a:', 'multiple_choice', '["Pseudorange","Baseline","DOP","Datum"]'::jsonb, 'Baseline', 'A baseline is the relative 3D vector between two receivers, the fundamental observation of static surveying.', 'easy', 'acc00005-0000-0000-0000-000000000005', 'acc05b06-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000012', 'A static baseline spec is 5 mm + 1 ppm. For a 10 km baseline, what is the expected error in millimeters?', 'numeric_input', '[]'::jsonb, '15', 'Error = 5 mm + (1 ppm x 10,000 m) = 5 + 10 = 15 mm.', 'medium', 'acc00005-0000-0000-0000-000000000005', 'acc05b06-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000013', 'In RTK, which solution status is required before recording survey-grade points?', 'multiple_choice', '["Autonomous","Float","Fixed","DGPS"]'::jsonb, 'Fixed', 'Only a fixed solution has resolved integer ambiguities and is accurate to a centimeter or two; float is not trustworthy.', 'easy', 'acc00005-0000-0000-0000-000000000005', 'acc05b07-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000014', 'Single-base RTK remains reliable at unlimited distance from the base.', 'true_false', '["True","False"]'::jsonb, 'False', 'Single-base RTK degrades beyond roughly 10-20 km as the atmosphere over base and rover diverges.', 'easy', 'acc00005-0000-0000-0000-000000000005', 'acc05b07-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000015', 'NGS OPUS returns coordinates by processing a submitted static file against:', 'multiple_choice', '["The almanac","Three CORS stations","A virtual reference station","The broadcast ephemeris only"]'::jsonb, 'Three CORS stations', 'OPUS processes the uploaded dual-frequency static file against three nearby CORS and returns NSRS coordinates.', 'medium', 'acc00005-0000-0000-0000-000000000005', 'acc05b09-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000016', 'A typical GNSS elevation mask is set to about:', 'multiple_choice', '["0 degrees","10-15 degrees","45 degrees","90 degrees"]'::jsonb, '10-15 degrees', 'A 10-15 degree mask suppresses low-elevation satellites that suffer the most atmospheric delay and multipath.', 'easy', 'acc00005-0000-0000-0000-000000000005', 'acc05b10-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000017', 'In a closed loop of baselines, the misclosure should ideally be:', 'multiple_choice', '["Equal to the longest baseline","Zero","Equal to the UERE","One ppm"]'::jsonb, 'Zero', 'A closed loop of vectors should sum to zero; a large misclosure flags a blunder in one baseline.', 'medium', 'acc00005-0000-0000-0000-000000000005', 'acc05b11-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000018', 'Which data model represents continuous phenomena such as elevation or imagery?', 'multiple_choice', '["Vector","Raster","Topology","Attribute table"]'::jsonb, 'Raster', 'Raster uses a grid of cells for continuous surfaces (DEM, imagery). Vector represents discrete features.', 'easy', 'acc00005-0000-0000-0000-000000000005', 'acc05b12-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000019', 'Assigning real-world coordinates to a scanned map by matching control points is called:', 'multiple_choice', '["Buffering","Georeferencing","Differencing","Clipping"]'::jsonb, 'Georeferencing', 'Georeferencing ties raster/scanned data to real coordinates so it overlays other layers.', 'easy', 'acc00005-0000-0000-0000-000000000005', 'acc05b13-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000020', 'Name the term for "data about the data" documenting source, datum, accuracy, and lineage.', 'short_answer', '[]'::jsonb, 'Metadata', 'Metadata documents source, datum, projection, accuracy, date, and lineage of a dataset.', 'easy', 'acc00005-0000-0000-0000-000000000005', 'acc05b13-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000021', 'A ground distance of 1000.00 ft is on a system with a combined scale factor of 0.99990. What is the grid distance in feet?', 'numeric_input', '[]'::jsonb, '999.90', 'D_grid = D_ground x CSF = 1000.00 x 0.99990 = 999.90 ft.', 'medium', 'acc00005-0000-0000-0000-000000000005', 'acc05b14-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3330-0000-0000-0000-000000000022', 'In much of Texas practice, surface (ground) coordinate systems are used so that:', 'multiple_choice', '["Grid distances exceed ground distances","CAD/plat distances match taped ground distances","The geoid is ignored","RTK is unnecessary"]'::jsonb, 'CAD/plat distances match taped ground distances', 'Texas often uses surface/low-distortion coordinates so that distances in CAD match ground measurements, avoiding grid-to-ground confusion.', 'hard', 'acc00005-0000-0000-0000-000000000005', 'acc05b14-0000-0000-0000-000000000001', ARRAY['buildout','module-33']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
