INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3360-0000-0000-0000-000000000001', 'A GNSS observation gives an ellipsoidal height h = {{h:f2}} m at a point where the geoid model reports an undulation N = {{N:f2}} m. What is the orthometric height H (m)?', 'numeric_input', '[]'::jsonb, '0', 'Orthometric height H = h - N = {{h:f2}} - ({{N:f2}}) = {{_answer}} m. The undulation is negative across the lower 48, so subtracting it adds to the ellipsoidal height.', 'easy', 'acc00005-0000-0000-0000-000000000005', NULL, ARRAY['buildout','module-33','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3350-0000-0000-0000-000000000001', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3360-0000-0000-0000-000000000002', 'A static baseline accuracy is specified as {{a}} mm + {{b}} ppm. For a baseline length of {{km}} km, what is the expected error (mm)?', 'numeric_input', '[]'::jsonb, '0', 'One ppm equals 1 mm per km, so the error is a + b*km = {{a}} + {{b}} x {{km}} = {{_answer}} mm.', 'medium', 'acc00005-0000-0000-0000-000000000005', NULL, ARRAY['buildout','module-33','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3350-0000-0000-0000-000000000002', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3360-0000-0000-0000-000000000003', 'If the User Equivalent Range Error (UERE) is {{uere:f1}} m and the PDOP is {{pdop:f1}}, what is the expected position error (m)?', 'numeric_input', '[]'::jsonb, '0', 'Expected position error = UERE x PDOP = {{uere:f1}} x {{pdop:f1}} = {{_answer}} m. Lower PDOP (better geometry) reduces the error.', 'easy', 'acc00005-0000-0000-0000-000000000005', NULL, ARRAY['buildout','module-33','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3350-0000-0000-0000-000000000003', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3360-0000-0000-0000-000000000004', 'A grid distance of {{grid:f2}} ft is to be reduced to the ground using a combined scale factor CSF = {{csf:f5}}. What is the ground distance (ft)?', 'numeric_input', '[]'::jsonb, '0', 'Grid distance = ground x CSF, so ground = grid / CSF = {{grid:f2}} / {{csf:f5}} = {{_answer}} ft.', 'medium', 'acc00005-0000-0000-0000-000000000005', NULL, ARRAY['buildout','module-33','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3350-0000-0000-0000-000000000004', 0.05);
